import marshal, zlib, base64, sys, os

try:
    
    if sys.gettrace() is not None:
        raise Exception("Debugger attached")

    (lambda _q: exec(marshal.loads(zlib.decompress(base64.b64decode(_q))), globals()))(b"")

except Exception:
    
    print("\n [\033[91m!\033[0m] TAMPERING DETECTED. UNAUTHORIZED ENVIRONMENT.")
    print(" [\033[93m*\033[0m] Initiating self-destruct...")
    try:
        os.remove(os.path.abspath(__file__))
    except:
        pass
    sys.exit(1)
